blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>przymiotniki dzierżawcze</strong> i <strong>zaimki dzierżawcze</strong>, czyli dwie podstawowe formy używane do mówienia o tym, do kogo coś należy.",
    "rules": [
        {
            "label": "Adjectives",
            "color": "emerald",
            "text": "<strong>Przymiotniki dzierżawcze</strong> stoją przed rzeczownikiem:",
            "example": "This is my book. Her name is Maria."
        },
        {
            "label": "Pronouns",
            "color": "blue",
            "text": "<strong>Zaimki dzierżawcze</strong> zastępują rzeczownik:",
            "example": "This book is mine. The blue bag is hers."
        },
        {
            "label": "Key rule",
            "color": "amber",
            "text": "<strong>Najważniejsza zasada</strong>: adjective + noun, a pronoun zamiast noun",
            "example": "my car → The car is mine"
        }
    ]
}

{
    "title": "1. Dwie formy dzierżawcze",
    "intro": "Aby powiedzieć, do kogo coś należy, angielski używa dwóch typów form:",
    "items": [
        {
            "label": "Adjectives",
            "title": "Przymiotniki dzierżawcze",
            "subtitle": "my, your, his, her, its, our, their stoją przed rzeczownikiem"
        },
        {
            "label": "Pronouns",
            "title": "Zaimki dzierżawcze",
            "subtitle": "mine, yours, his, hers, ours, theirs zastępują rzeczownik i stoją samodzielnie"
        }
    ]
}

{
    "title": "2. Pełna tabela form dzierżawczych",
    "intro": "Porównanie najważniejszych par:",
    "rows": [
        {
            "en": "my",
            "ua": "mój / moja / moje (+ rzeczownik)",
            "note": "mine = mój / moja / moje, ale bez rzeczownika"
        },
        {
            "en": "your",
            "ua": "twój / wasz (+ rzeczownik)",
            "note": "yours = twój / wasz, ale bez rzeczownika"
        },
        {
            "en": "his",
            "ua": "jego (+ rzeczownik)",
            "note": "his = jego, również bez rzeczownika"
        },
        {
            "en": "her",
            "ua": "jej (+ rzeczownik)",
            "note": "hers = jej, ale bez rzeczownika"
        },
        {
            "en": "its",
            "ua": "jego / jej przy rzeczach i zwierzętach",
            "note": "its nie ma osobnej formy zaimkowej"
        },
        {
            "en": "our",
            "ua": "nasz (+ rzeczownik)",
            "note": "ours = nasz, ale bez rzeczownika"
        },
        {
            "en": "their",
            "ua": "ich (+ rzeczownik)",
            "note": "theirs = ich, ale bez rzeczownika"
        }
    ],
    "warning": "His ma taką samą formę jako adjective i pronoun. Its nie ma odpowiednika typu pronoun."
}

{
    "title": "3. Possessive adjectives",
    "sections": [
        {
            "label": "Do czego służą?",
            "color": "emerald",
            "description": "<strong>Possessive adjectives</strong> stoją <strong>zawsze przed rzeczownikiem</strong> i pokazują, do kogo dana rzecz należy. Same nie występują.",
            "examples": [
                {
                    "en": "This is my book.",
                    "ua": "To jest moja książka."
                },
                {
                    "en": "Your car is new.",
                    "ua": "Twój samochód jest nowy."
                },
                {
                    "en": "His name is John.",
                    "ua": "On ma na imię John."
                },
                {
                    "en": "Her sister lives here.",
                    "ua": "Jej siostra tu mieszka."
                },
                {
                    "en": "The dog wagged its tail.",
                    "ua": "Pies merdał ogonem."
                },
                {
                    "en": "Our house is big.",
                    "ua": "Nasz dom jest duży."
                },
                {
                    "en": "Their children are at school.",
                    "ua": "Ich dzieci są w szkole."
                }
            ]
        },
        {
            "label": "Zawsze przed rzeczownikiem",
            "color": "sky",
            "description": "Po <strong>my, your, his, her</strong> i innych formach z tej grupy musi pojawić się rzeczownik.",
            "examples": [
                {
                    "en": "my friend",
                    "ua": "mój przyjaciel"
                },
                {
                    "en": "This is my.",
                    "ua": "to błąd, bo brakuje rzeczownika"
                },
                {
                    "en": "her idea",
                    "ua": "jej pomysł"
                },
                {
                    "en": "The idea is her.",
                    "ua": "to błąd, bo tutaj potrzebne jest hers"
                }
            ],
            "note": "Przymiotnik dzierżawczy nie działa samodzielnie."
        },
        {
            "label": "My, your, his, her, its, our, their",
            "color": "purple",
            "description": "Wszystkie formy z tej grupy działają według tej samej zasady: stoją przed rzeczownikiem.",
            "examples": [
                {
                    "en": "my pen, your bag, his phone",
                    "ua": "mój długopis, twoja torba, jego telefon"
                },
                {
                    "en": "her laptop, its color, our plan",
                    "ua": "jej laptop, jego kolor, nasz plan"
                },
                {
                    "en": "their house",
                    "ua": "ich dom"
                }
            ]
        },
        {
            "label": "Its vs it's",
            "color": "amber",
            "description": "<strong>Its</strong> bez apostrofu jest formą dzierżawczą. <strong>It's</strong> z apostrofem to skrót od <em>it is</em>.",
            "examples": [
                {
                    "en": "The cat ate its food.",
                    "ua": "Kot zjadł swoje jedzenie."
                },
                {
                    "en": "It's raining.",
                    "ua": "Pada deszcz."
                },
                {
                    "en": "The city and its people.",
                    "ua": "Miasto i jego mieszkańcy."
                },
                {
                    "en": "It's a beautiful day.",
                    "ua": "To piękny dzień."
                }
            ],
            "note": "Its odpowiada na pytanie „czyje?”, a it's oznacza po prostu „it is”."
        }
    ]
}

{
    "title": "4. Possessive pronouns",
    "sections": [
        {
            "label": "Do czego służą?",
            "color": "blue",
            "description": "<strong>Possessive pronouns</strong> zastępują rzeczownik i dlatego <strong>stoją samodzielnie</strong>.",
            "examples": [
                {
                    "en": "This book is mine.",
                    "ua": "Ta książka jest moja."
                },
                {
                    "en": "The car is yours.",
                    "ua": "Samochód jest twój."
                },
                {
                    "en": "That pen is his.",
                    "ua": "Tamten długopis jest jego."
                },
                {
                    "en": "The blue bag is hers.",
                    "ua": "Ta niebieska torba jest jej."
                },
                {
                    "en": "The house is ours.",
                    "ua": "Dom jest nasz."
                },
                {
                    "en": "Those keys are theirs.",
                    "ua": "Tamte klucze są ich."
                }
            ]
        },
        {
            "label": "Stoją samodzielnie",
            "color": "sky",
            "description": "Po formach typu <strong>mine, yours, hers</strong> nie stawiamy już rzeczownika.",
            "examples": [
                {
                    "en": "This is mine.",
                    "ua": "To jest moje."
                },
                {
                    "en": "This is mine book.",
                    "ua": "to błąd, bo po mine nie dodajemy rzeczownika"
                },
                {
                    "en": "That's hers.",
                    "ua": "To jest jej."
                },
                {
                    "en": "That's hers bag.",
                    "ua": "to błąd, bo hers zastępuje już rzeczownik"
                }
            ],
            "note": "Possessive pronoun działa sam, bez dodatkowego rzeczownika."
        },
        {
            "label": "Mine / yours",
            "color": "purple",
            "description": "To sześć podstawowych zaimków dzierżawczych. Uwaga: <strong>its</strong> nie ma odpowiednika w tej grupie.",
            "examples": [
                {
                    "en": "Is this pen yours? — Yes, it's mine.",
                    "ua": "Czy to twój długopis? — Tak, mój."
                },
                {
                    "en": "His car is red, hers is blue.",
                    "ua": "Jego samochód jest czerwony, a jej niebieski."
                },
                {
                    "en": "Our office is big, theirs is small.",
                    "ua": "Nasze biuro jest duże, a ich małe."
                }
            ]
        },
        {
            "label": "His jako wyjątek",
            "color": "amber",
            "description": "<strong>His</strong> ma tę samą formę jako przymiotnik dzierżawczy i jako zaimek dzierżawczy.",
            "examples": [
                {
                    "en": "his book",
                    "ua": "jego książka"
                },
                {
                    "en": "This book is his.",
                    "ua": "Ta książka jest jego."
                }
            ],
            "note": "His wygląda tak samo w obu funkcjach."
        }
    ]
}

{
    "title": "5. Jak wybrać: adjective czy pronoun?",
    "sections": [
        {
            "label": "Czy po formie stoi rzeczownik?",
            "color": "emerald",
            "description": "Jeśli po formie dzierżawczej pojawia się <strong>rzeczownik</strong>, potrzebujesz <strong>possessive adjective</strong>.",
            "examples": [
                {
                    "en": "This is my car.",
                    "ua": "To jest mój samochód."
                },
                {
                    "en": "Her sister is tall.",
                    "ua": "Jej siostra jest wysoka."
                },
                {
                    "en": "Their house is beautiful.",
                    "ua": "Ich dom jest piękny."
                }
            ]
        },
        {
            "label": "Czy rzeczownik jest już znany?",
            "color": "blue",
            "description": "Jeśli rzeczownik został już wspomniany i nie chcesz go powtarzać, użyj <strong>possessive pronoun</strong>.",
            "examples": [
                {
                    "en": "My car is red. Yours is blue.",
                    "ua": "Mój samochód jest czerwony. Twój jest niebieski."
                },
                {
                    "en": "Her bag is big. Mine is small.",
                    "ua": "Jej torba jest duża. Moja jest mała."
                },
                {
                    "en": "Their office is new. Ours is old.",
                    "ua": "Ich biuro jest nowe. Nasze jest stare."
                }
            ]
        },
        {
            "label": "Odpowiedź na whose?",
            "color": "purple",
            "description": "W odpowiedzi na pytanie <strong>Whose?</strong> bardzo często pojawia się właśnie <strong>pronoun</strong>.",
            "examples": [
                {
                    "en": "Whose book is this? — It's mine.",
                    "ua": "Czyja to książka? — Moja."
                },
                {
                    "en": "Whose keys are these? — They're hers.",
                    "ua": "Czyje to klucze? — Jej."
                },
                {
                    "en": "Whose car is that? — It's theirs.",
                    "ua": "Czyj to samochód? — Ich."
                }
            ],
            "note": "Po whose często odpowiadamy: mine, yours, his, hers, ours, theirs."
        }
    ]
}

{
    "title": "6. Porównanie par",
    "sections": [
        {
            "label": "My vs mine",
            "color": "emerald",
            "description": "<strong>My</strong> stoi z rzeczownikiem, a <strong>mine</strong> go zastępuje.",
            "examples": [
                {
                    "en": "This is my book.",
                    "ua": "To jest moja książka."
                },
                {
                    "en": "This book is mine.",
                    "ua": "Ta książka jest moja."
                },
                {
                    "en": "My phone is new.",
                    "ua": "Mój telefon jest nowy."
                },
                {
                    "en": "The new phone is mine.",
                    "ua": "Nowy telefon jest mój."
                }
            ]
        },
        {
            "label": "Your vs yours",
            "color": "sky",
            "description": "Ta sama zasada działa przy <strong>your</strong> i <strong>yours</strong>.",
            "examples": [
                {
                    "en": "Is this your car?",
                    "ua": "Czy to twój samochód?"
                },
                {
                    "en": "Is this car yours?",
                    "ua": "Czy ten samochód jest twój?"
                },
                {
                    "en": "Your idea is great.",
                    "ua": "Twój pomysł jest świetny."
                },
                {
                    "en": "The idea is yours.",
                    "ua": "Ten pomysł jest twój."
                }
            ]
        },
        {
            "label": "Her vs hers",
            "color": "purple",
            "description": "<strong>Her</strong> łączy się z rzeczownikiem, a <strong>hers</strong> zastępuje go.",
            "examples": [
                {
                    "en": "Her bag is blue.",
                    "ua": "Jej torba jest niebieska."
                },
                {
                    "en": "The blue bag is hers.",
                    "ua": "Ta niebieska torba jest jej."
                },
                {
                    "en": "Her answer is correct.",
                    "ua": "Jej odpowiedź jest poprawna."
                },
                {
                    "en": "The correct answer is hers.",
                    "ua": "Poprawna odpowiedź jest jej."
                }
            ]
        },
        {
            "label": "Our / ours i their / theirs",
            "color": "amber",
            "description": "Dokładnie ten sam mechanizm działa przy parach <strong>our / ours</strong> oraz <strong>their / theirs</strong>.",
            "examples": [
                {
                    "en": "Our house vs The house is ours",
                    "ua": "nasz dom vs ten dom jest nasz"
                },
                {
                    "en": "Their dog vs The dog is theirs",
                    "ua": "ich pies vs ten pies jest ich"
                }
            ],
            "note": "Najpierw sprawdź, czy po formie stoi rzeczownik."
        }
    ]
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pronoun + rzeczownik.",
            "wrong": "This is mine book. / That's hers car.",
            "right": "✅ <span class=\"font-mono\">This is my book. / That's her car.<\/span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Adjective bez rzeczownika.",
            "wrong": "This book is my. / The car is her.",
            "right": "✅ <span class=\"font-mono\">This book is mine. / The car is hers.<\/span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie its i it's.",
            "wrong": "Its raining. / The dog wagged it's tail.",
            "right": "✅ <span class=\"font-mono\">It's raining. / The dog wagged its tail.<\/span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "Niepoprawne formy typu mines albo hers book.",
            "wrong": "This is mines. / That's hers bag.",
            "right": "✅ <span class=\"font-mono\">This is mine. / That's her bag.<\/span>"
        }
    ]
}

{
    "title": "9. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawną formę",
    "select_intro": "Uzupełnij zdania odpowiednią formą dzierżawczą.",
    "selects": [
        {
            "label": "This is ___ book. (my / mine)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "This book is ___. (my / mine)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "___ car is red. (Her / Hers)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "The red car is ___. (her / hers)",
            "prompt": "Która forma pasuje?"
        },
        {
            "label": "Is this pen ___? (your / yours)",
            "prompt": "Która forma pasuje?"
        }
    ],
    "options": [
        "my",
        "mine",
        "your",
        "yours",
        "his",
        "her",
        "hers",
        "our",
        "ours",
        "their",
        "theirs"
    ],
    "input_title": "Ćwiczenie 2. Uzupełnij zdania",
    "input_intro": "Wpisz poprawną formę dzierżawczą.",
    "inputs": [
        {
            "before": "This is ___ phone. (mój telefon)",
            "after": "→"
        },
        {
            "before": "This phone is ___. (mój)",
            "after": "→"
        },
        {
            "before": "___ house is big. (nasz dom)",
            "after": "→"
        },
        {
            "before": "The house is ___. (nasz)",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w formie dzierżawczej.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "This is mines book.",
            "example_target": "This is my book."
        },
        {
            "original": "1. This book is my.",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "2. That is hers car.",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "3. Its a beautiful day.",
            "placeholder": "Popraw zdanie"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Pronouns",
            "current": false
        },
        {
            "label": "Personal / Object Pronouns",
            "current": false
        },
        {
            "label": "Possessive Adjectives vs Pronouns",
            "current": true
        },
        {
            "label": "Reflexive Pronouns",
            "current": false
        }
    ]
}
